class Solution(object):
    def distMoney(self, money, children):
        if money < children:
            return -1
        money -= children
        k = min(money // 7, children)
        money -= k * 7
        remaining = children - k
        if remaining == 0:
            if money > 0:
                k -= 1
            return k
        if remaining == 1 and money == 3:
            k -= 1
        return k
